"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[63],{7762(e,o,t){t.r(o),t.d(o,{assets:()=>l,contentTitle:()=>r,default:()=>u,frontMatter:()=>s,metadata:()=>n,toc:()=>h});const n=JSON.parse('{"type":"mdx","permalink":"/wedding_website/sermon","source":"@site/src/pages/sermon.md","title":"Wedding Exhortation for Haotian and Jianing (Kara)","description":"Here is the complete English translation of the revised wedding sermon. I made sure to preserve the warm, pastoral tone and the theological depth of the original text:","frontMatter":{},"unlisted":false}');var i=t(4848),a=t(8453);const s={},r="Wedding Exhortation for Haotian and Jianing (Kara)",l={},h=[{value:"Wedding Exhortation for Haotian and Jianing (Kara)",id:"wedding-exhortation-for-haotian-and-jianing-kara-1",level:2},{value:"Introduction",id:"introduction",level:3},{value:"First, the love in marriage is a sublimation of love, moving from romance to covenant.",id:"first-the-love-in-marriage-is-a-sublimation-of-love-moving-from-romance-to-covenant",level:4},{value:"Second, there is no comparison in love.",id:"second-there-is-no-comparison-in-love",level:4},{value:"Third, love is not self-centered; it considers others more.",id:"third-love-is-not-self-centered-it-considers-others-more",level:4},{value:"Lastly, love always maintains an optimistic evaluation and expectation of people.",id:"lastly-love-always-maintains-an-optimistic-evaluation-and-expectation-of-people",level:4},{value:"Conclusion",id:"conclusion",level:3}];function d(e){const o={br:"br",h1:"h1",h2:"h2",h3:"h3",h4:"h4",header:"header",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(o.header,{children:(0,i.jsx)(o.h1,{id:"wedding-exhortation-for-haotian-and-jianing-kara",children:"Wedding Exhortation for Haotian and Jianing (Kara)"})}),"\n",(0,i.jsx)(o.p,{children:"Here is the complete English translation of the revised wedding sermon. I made sure to preserve the warm, pastoral tone and the theological depth of the original text:"}),"\n",(0,i.jsx)(o.h2,{id:"wedding-exhortation-for-haotian-and-jianing-kara-1",children:"Wedding Exhortation for Haotian and Jianing (Kara)"}),"\n",(0,i.jsxs)(o.p,{children:[(0,i.jsx)(o.strong,{children:"Scriptures:"})," 1 Corinthians 13:4-13, 1 John 4:9-12, 18-19, Proverbs 3:5-6",(0,i.jsx)(o.br,{}),"\n",(0,i.jsx)(o.strong,{children:"Date:"})," March 21, 2026",(0,i.jsx)(o.br,{}),"\n",(0,i.jsx)(o.strong,{children:"Speaker:"})," Pastor Ruda Pan"]}),"\n",(0,i.jsx)(o.h3,{id:"introduction",children:"Introduction"}),"\n",(0,i.jsx)(o.p,{children:"Congratulations to Haotian and Jianing as you make your marriage vows before God today and enter into the holy estate of matrimony. Praise the Lord for His wonderful guidance in your lives, leading you from meeting at Purdue, falling in love, and dating, to step-by-step entering into marriage. Looking back at this journey, we must truly say that your marriage is a testament to God's wondrous leading."}),"\n",(0,i.jsx)(o.p,{children:"Congratulations also to both sets of parents, Pastor and Mrs. Deng, and Mr. and Mrs. Fu. You must be exceptionally joyful today seeing Haotian and Jianing joined in marriage. Their marriage is an extension of your two families. We see Haotian and Jianing coming from their respective families; after you as parents have raised them to adulthood, they are stepping out of their original families to build a new one. The Book of Genesis says that in marriage, a man shall leave his father and mother and the two shall become one flesh. From one perspective, this is the time for parents to let go, allowing their children to be independent and form their own families, as this is a necessary path in a child's growth. From another perspective, when we as parents willingly let go and entrust our children to their spouses, we truly gain them. We not only do not lose our own children, but we also gain another son or daughter."}),"\n",(0,i.jsx)(o.p,{children:"Marriage is the most important institution established by God in human society. It is the very first human relationship established by Him since creation, and God was involved in every part of its establishment. It was God who created Adam and Eve, and God who brought the two together, just as God wondrously brought Haotian and Jianing together, and it is God Himself who officiates their union. Therefore, this relationship has been sacred from the very beginning. Today, you are walking this sacred path together."}),"\n",(0,i.jsx)(o.p,{children:'When discussing the wedding proceedings with them, I asked if there were any specific scriptures they wanted to share at the wedding. To my surprise, they listed four passages, which gave me quite a challenging task. 1 Corinthians 13 has always been known as the "Love Chapter," and I think this passage is especially meaningful in a wedding. Furthermore, in the weddings I have officiated this year, three couples have already chosen the phrase "There is no fear in love" from 1 John 4:18. Love is the most important element in marriage, and "no fear" is a crucial element in practicing love. 1 John 4:10-12 speaks of the great love of the Lord Jesus dying on the cross; this is the source and driving force of our ability to truly love one another, and it is also our ultimate example. Proverbs 3:5-6 reminds us that we cannot truly love our spouses by relying solely on ourselves; we need to trust in our God with all our hearts. After briefly summarizing these four passages, let us reflect on them in detail.'}),"\n",(0,i.jsx)(o.p,{children:'1 Corinthians 13:13 mentions: "And now these three remain: faith, hope and love." Where do these three things remain? They remain in our lives and daily living. Faith is the foundation of our lives, hope is the driving force of our lives, and what about love? Love is the content of our lives.'}),"\n",(0,i.jsx)(o.p,{children:'These three enduring things also remain in our marriages. So we can say that faith is the foundation of marriage, hope is the driving force of marriage, and love is the content of marriage. If you take love out of your marriage, there would be nothing left. Therefore, reflecting on "love" today is extremely important.'}),"\n",(0,i.jsx)(o.p,{children:'Moreover, Paul goes on to say: "But the greatest of these is love." "Greatest" does not refer to status or power, but to importance. In marriage, love is the most important thing. In fact, Paul emphasizes throughout 1 Corinthians 13 that love is the greatest. The passage begins by saying: "If I... but do not have love, I am nothing..."'}),"\n",(0,i.jsx)(o.p,{children:"The reason love is the greatest and most important is that love never fails. So in the latter half of 1 Corinthians 13, it mentions what will end and what will cease, and even in eternity, faith and hope will no longer be needed\u2014only love never ends. This once again demonstrates the value of love, especially its value in marriage."}),"\n",(0,i.jsx)(o.p,{children:'Therefore, Haotian and Jianing, you must learn the lessons of love in your marriage. Marriage is an important setting for learning to love one another. Perhaps, like countless couples in the world, you are both imperfect, but I hope that through this "school of love" that is marriage, you will increasingly learn how to love each other, so that you can increasingly enjoy being in love. You will also increasingly learn how to love God together and enjoy your loving relationship with God together.'}),"\n",(0,i.jsx)(o.p,{children:"Reflecting on 1 Corinthians 13, especially verses 4-7, is undoubtedly a wonderful starting point for learning. So, we should really unpack this passage. How long would it take if we were to thoroughly study this scripture? Would two hours be enough? Saying this might have startled everyone! In a wedding, considering that the bride and groom are standing, along with the groomsmen and bridesmaids standing beside them, time does not allow us to speak for that long, lest someone faints. So do not worry, we will just scratch the surface. I would like to raise a few points here:"}),"\n",(0,i.jsx)(o.h4,{id:"first-the-love-in-marriage-is-a-sublimation-of-love-moving-from-romance-to-covenant",children:"First, the love in marriage is a sublimation of love, moving from romance to covenant."}),"\n",(0,i.jsx)(o.p,{children:"During your dating process, you were certainly attracted to each other, whether you found the other beautiful and elegant, or kind and gentle. This attraction led you step-by-step into marriage. In reality, the closer you get, the more you will realize: while the marital relationship must certainly continue to be romantic, it cannot be built solely on romance. Because we are all human, we all have unlovable traits, and we all have areas where we need to adjust or adapt to each other. In a relationship as close-knit as marriage, these unlovable traits are easily magnified and scrutinized."}),"\n",(0,i.jsx)(o.p,{children:"When love is built only on romance, once those unlovable traits are seen, the romantic feeling will fade, and will love still be there? The Bible says, love is patient, love is kind. This is the attitude we should have when we find the other person unlovable. For ordinary people, when we encounter someone unlovable, we just stay away from them and interact less. But this is not the biblical principle of loving others, and it is certainly not the principle of marriage. In marriage, when you see your spouse's flaws, you must be patient and kind. Patience is passive endurance; kindness is active goodness. Patience alone is not enough; you must also treat each other's flaws with kindness."}),"\n",(0,i.jsx)(o.p,{children:'That is why it later says, "[love] always protects, always trusts, always hopes, always perseveres." How can you achieve this? You must let your love be based on a "covenant," not just on feelings or chemistry. Today, you are making vows of love before God. For you, love is this vow\u2014it is loving not only the lovable parts of the other person but also the unlovable parts.'}),"\n",(0,i.jsx)(o.p,{children:"Let us look back at Jesus' love for us. He loves us not because we are lovable, but because He has an unconditional love, a covenantal love, a fully accepting and fully committed love for us. This is the ultimate example for a husband and wife. This is what 1 John 4:10-12 says: we are able to love because God first loved us. Through the unconditional love of Jesus Christ, we are inspired and thereby empowered to love God, and even more empowered to love our spouse. Marriage is an education in love; through loving your spouse, you learn about the Lord Jesus' unconditional love for us. Only in this way can we be truly patient and kind."}),"\n",(0,i.jsx)(o.h4,{id:"second-there-is-no-comparison-in-love",children:"Second, there is no comparison in love."}),"\n",(0,i.jsx)(o.p,{children:"Will there be comparisons between husband and wife? What will be compared? Who is stronger? Who is more capable? Whose opinion prevails? Who is more important? Who manages the money? Who spends the money or who spends more? ... But true love does not compare; it does not care about these issues."}),"\n",(0,i.jsx)(o.p,{children:"So the Bible says: love does not envy, it does not boast, it is not proud. These all stem from comparison. True love means I hope my spouse is better, more excellent, and more important than I am. This cannot just be lip service; when the other person truly excels, I am genuinely happy from the bottom of my heart. True love is being willing to do more for my spouse to let them shine, rather than waiting for them to do more for me so that I can shine."}),"\n",(0,i.jsx)(o.h4,{id:"third-love-is-not-self-centered-it-considers-others-more",children:"Third, love is not self-centered; it considers others more."}),"\n",(0,i.jsx)(o.p,{children:'Here Paul mentions love "does not dishonor others" (or act unbecomingly). In 1 Corinthians, this word is also used to describe not following dining etiquette at formal banquets or not dressing appropriately (such as wearing shorts or slippers). When these things happen, the person involved might say, "I don\'t care. As long as I like it, why not?" This is self-centeredness. Furthermore, "it is not self-seeking, it is not easily angered, it keeps no record of wrongs" are all expressions of being self-centered and disregarding others.'}),"\n",(0,i.jsx)(o.p,{children:"Love is exactly the opposite; love puts the needs of others before one's own. It is just like Jesus on the night before He departed to the Father; knowing He was about to face the immense challenge of the cross, He did not consider Himself first. During the supper, He considered the disciples' needs first, washing their feet, encouraging them, comforting them, and interceding for them. Between husband and wife, you must also put your spouse's needs before your own, prioritize your spouse's feelings over your own, and consider your spouse's opinions first. Besides God, you must place your spouse as your absolute top priority."}),"\n",(0,i.jsx)(o.h4,{id:"lastly-love-always-maintains-an-optimistic-evaluation-and-expectation-of-people",children:"Lastly, love always maintains an optimistic evaluation and expectation of people."}),"\n",(0,i.jsx)(o.p,{children:"I said at the beginning that people are not always lovable; to put it plainly, everyone has flaws. Of course, sometimes our assessments are not objective\u2014we tend to think that traits similar to ours are strengths, and traits different from ours are weaknesses. But even if the other person genuinely has flaws, how should we view our spouse's shortcomings? We must bear with them. Of course, bearing with them does not mean indulgence, at least not on major issues of right and wrong. However, you must believe that they have the possibility to change and the potential to grow. Only then will you give them space and hold onto hope for them. Even if it takes a long time, you can maintain faith and hope, and persevere in all things."}),"\n",(0,i.jsx)(o.p,{children:'This relates to what John mentions in 1 John 4:17-19: "There is no fear in love." This phrase is first applied to our relationship with God. Those of us who come to the US to study have been top students since childhood. Others have high expectations of us, our parents have high expectations of us, and we even have high expectations of ourselves. Having high expectations is a good thing, but high expectations often cause us to live under immense pressure, and even in fear. We fear that we are not good enough, we fear others will think we are not good enough, and we fear our spouses will think we are not good enough.'}),"\n",(0,i.jsx)(o.p,{children:'But "there is no fear in love" expresses that God saves us not because we are good or excellent; God saves us solely because of His grace and His love. Even after becoming Christians, we still have many flaws and weaknesses; even after becoming husband and wife, we are still far from being able to love each other with a completely selfless love.'}),"\n",(0,i.jsx)(o.p,{children:"But we do not need to fear. Our God is not a God who is constantly grading us and deciding on rewards and punishments. This is not to say He has lowered His standards, but rather that the sacrificial love of Jesus Christ has already borne the debt of our imperfections."}),"\n",(0,i.jsx)(o.p,{children:"Similarly, in marriage, \"there is no fear in love.\" As we mentioned earlier, you are still far from maturity. Although you may not yet be able to fully live out selfless love right now, there is no fear in love. You do not need to live under the pressure of failing to meet God's standards. On the contrary, in God's tolerance and Christ's salvation, you can find freedom and continuously move towards maturity through learning."}),"\n",(0,i.jsx)(o.p,{children:'"There is no fear in love" is also applicable to your relationship with each other. If we are certain that in Christ\'s salvation, God has given us the opportunity to grow, then we should also be willing to give our spouses the opportunity to grow amidst their imperfections. I want to emphasize again, both of you have been seen as highly excellent in the eyes of others since childhood, always carrying high expectations and successfully meeting the expectations of parents and others. People with such backgrounds might have very strong opinions and unconsciously hold extremely high expectations and demands for themselves and those around them\u2014especially for their spouses.'}),"\n",(0,i.jsx)(o.p,{children:'However, in your post-marital interactions, please never forget: have a little more tolerance and understanding, and give each other some space to grow. This way, it will be easier for you to experience what it means that "there is no fear in love," and it will be easier to grow together in love. Because this is exactly how our God treats us.'}),"\n",(0,i.jsx)(o.h3,{id:"conclusion",children:"Conclusion"}),"\n",(0,i.jsx)(o.p,{children:"I cannot possibly cover the full meaning and practice of love today. But even speaking just this little bit, we must ask: Is this easy to do? Have we done it? What should we do if we can't?"}),"\n",(0,i.jsx)(o.p,{children:"Learning to love is not an easy lesson. We know well that we certainly cannot do it on our own, but we have God as our reliance. Living out love is His expectation of us; and within His expectation, there is also His promise that He will surely help us live it out. Therefore, as the two of you enter into each coming day, you will find that loving each other completely is full of challenges. However, when you trust in the Lord with all your heart, you will certainly experience the power that comes from God\u2014the power to love."}),"\n",(0,i.jsx)(o.p,{children:"More importantly, in our lives, there is an example of love set before us, and that is the Lord Jesus. He came to earth, died on the cross for us, so that our sins may be forgiven, so that we may be reconciled with God, and so that we may have a new life. He loves us with unconditional love, with a love of tolerance and forgiveness, with an unchanging covenantal love, and with a fully sacrificial love. His salvation brings us new life, empowering us to learn to love and to live out love. Most importantly, He became our example of loving one another."}),"\n",(0,i.jsx)(o.p,{children:"Therefore, Haotian and Jianing, in your future home, remember to always draw near to God, frequently think of the Lord Jesus, and let His love become alive in your daily lives."}),"\n",(0,i.jsx)(o.p,{children:"Today you enter into marriage, and the lesson of learning the love of marriage has just begun. I believe you will learn it very well because God is with you, and He will personally guide you in learning this lesson. Whether you are at Purdue, in Boston, or anywhere else in the future, there will be many brothers and sisters accompanying you. May you continually grow in God's grace and in the fellowship of brothers and sisters in the church, attaining to the whole measure of the fullness of Christ."})]})}function u(e={}){const{wrapper:o}={...(0,a.R)(),...e.components};return o?(0,i.jsx)(o,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},8453(e,o,t){t.d(o,{R:()=>s,x:()=>r});var n=t(6540);const i={},a=n.createContext(i);function s(e){const o=n.useContext(a);return n.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function r(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),n.createElement(a.Provider,{value:o},e.children)}}}]);